from IPython.display import display, HTML

kpi_html = f"""
&lt;div class="kpi-row"&gt;
  &lt;div class="kpi-card kpi-blue"&gt;
    &lt;div class="kpi-icon"&gt;👥&lt;/div&gt;
    &lt;span class="kpi-value"&gt;{total_pop:,}&lt;/span&gt;
    &lt;span class="kpi-label"&gt;Total Population (2023)&lt;/span&gt;
