&lt;/div&gt;
&lt;div class="kpi-row"&gt;
  &lt;div class="kpi-card kpi-gold"&gt;
    &lt;div class="kpi-icon"&gt;📊&lt;/div&gt;
    &lt;span class="kpi-value"&gt;{avg_pop:,}&lt;/span&gt;
    &lt;span class="kpi-label"&gt;Avg per Department (2023)&lt;/span&gt;
  &lt;/div&gt;
  &lt;div class="kpi-card kpi-green"&gt;
    &lt;div class="kpi-icon"&gt;📈&lt;/div&gt;
    &lt;span class="kpi-value"&gt;{median_pop:,}&lt;/span&gt;
    &lt;span class="kpi-label"&gt;Median Population (2023)&lt;/span&gt;
  &lt;/div&gt;
  &lt;div class="kpi-card kpi-purple"&gt;
    &lt;div class="kpi-icon"&gt;🏆&lt;/div&gt;
    &lt;span class="kpi-value"&gt;{most_pop}&lt;/span&gt;
    &lt;span class="kpi-label"&gt;Most Populous — {most_pop_val:,}&lt;/span&gt;
  &lt;/div&gt;
  &lt;div class="kpi-card kpi-red"&gt;
    &lt;div class="kpi-icon"&gt;📉&lt;/div&gt;
    &lt;span class="kpi-value"&gt;{least_pop}&lt;/span&gt;
    &lt;span class="kpi-label"&gt;Least Populous — {least_pop_val:,}&lt;/span&gt;
  &lt;/div&gt;
&lt;/div&gt;
"""
display(HTML(kpi_html))





